import React, { useState, useMemo, useRef, useEffect } from "react";
import {
  Search, ScanLine, Plus, Minus, Trash2, X, Wifi, WifiOff, RefreshCw,
  Store, Banknote, CreditCard, ArrowLeftRight, Smartphone, Check, Leaf,
} from "lucide-react";

/* Guapa Gourmet Market — POS prototype
   Paleta: verde bosque (orgánico) sobre blanco cálido, acento miel.
   Todo en memoria: en producción esto vive en la base local offline de cada caja. */

// Logo oficial de Guapa Gourmet Market (círculo transparente, embebido).
const LOGO = "data:image/png;base64,";

// Paleta oficial tomada del logo.
const C = {
  bg: "#FAF5EC",         // crema
  surface: "#FFFFFF",
  ink: "#2E332C",
  muted: "#7C8279",
  line: "#ECE4D5",
  green: "#5F7A64",       // salvia fuerte (acciones / texto sobre claro)
  greenDark: "#4C6351",
  greenSoft: "#EAF0E8",
  sage: "#9AAD9C",        // verde del logo
  honey: "#A97D77",       // acento: rosa empolvado de marca
  honeySoft: "#F5E7E4",
};

const money = (n) =>
  new Intl.NumberFormat("es-CO", {
    style: "currency", currency: "COP", maximumFractionDigits: 0,
  }).format(Math.round(n));

const PRODUCTS = [
  { id: 1, nombre: "Granola artesanal 500 g", cat: "Cereales", precio: 18900, iva: 0.19, cb: "7700000000017" },
  { id: 2, nombre: "Miel de abejas pura 500 g", cat: "Endulzantes", precio: 24500, iva: 0.05, cb: "7700000000024" },
  { id: 3, nombre: "Almendras naturales 250 g", cat: "Frutos secos", precio: 21900, iva: 0.19, cb: "7700000000031" },
  { id: 4, nombre: "Aguacate Hass (und)", cat: "Frutas y verduras", precio: 3500, iva: 0, cb: "7700000000048" },
  { id: 5, nombre: "Pan de masa madre integral", cat: "Panadería", precio: 12800, iva: 0.05, cb: "7700000000055" },
  { id: 6, nombre: "Té verde orgánico x20", cat: "Bebidas", precio: 15600, iva: 0.19, cb: "7700000000062" },
  { id: 7, nombre: "Aceite de oliva extra virgen 500 ml", cat: "Aceites", precio: 38900, iva: 0.19, cb: "7700000000079" },
  { id: 8, nombre: "Yogur griego natural 150 g", cat: "Lácteos", precio: 5200, iva: 0.05, cb: "7700000000086" },
  { id: 9, nombre: "Quinua orgánica 500 g", cat: "Granos", precio: 16400, iva: 0, cb: "7700000000093" },
  { id: 10, nombre: "Mantequilla de maní natural", cat: "Untables", precio: 19800, iva: 0.19, cb: "7700000000109" },
  { id: 11, nombre: "Chía en semillas 250 g", cat: "Semillas", precio: 11500, iva: 0.19, cb: "7700000000116" },
  { id: 12, nombre: "Kombucha jengibre 330 ml", cat: "Bebidas", precio: 9900, iva: 0.19, cb: "7700000000123" },
];

const CATS = ["Todos", ...Array.from(new Set(PRODUCTS.map((p) => p.cat)))];

const METODOS = [
  { id: "efectivo", label: "Efectivo", icon: Banknote, color: "#5F7A64" },
  { id: "tarjeta", label: "Tarjeta", icon: CreditCard, color: "#3B5566" },
  { id: "transferencia", label: "Transferencia", icon: ArrowLeftRight, color: "#2B6CB0" },
  { id: "nequi", label: "Nequi", icon: Smartphone, color: "#8B1E67" },
  { id: "daviplata", label: "Daviplata", icon: Smartphone, color: "#C4262E" },
];

export default function POS() {
  const [query, setQuery] = useState("");
  const [cat, setCat] = useState("Todos");
  const [cart, setCart] = useState([]);
  const [descPct, setDescPct] = useState(0);
  const [online, setOnline] = useState(true);
  const [pendientes, setPendientes] = useState(0);
  const [ventasHoy, setVentasHoy] = useState({ n: 0, total: 0 });
  const [pagando, setPagando] = useState(false);
  const [toast, setToast] = useState(null);
  const searchRef = useRef(null);

  useEffect(() => {
    const t = setTimeout(() => searchRef.current?.focus(), 200);
    return () => clearTimeout(t);
  }, []);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return PRODUCTS.filter((p) => {
      const okCat = cat === "Todos" || p.cat === cat;
      const okQ = !q || p.nombre.toLowerCase().includes(q) || p.cb.includes(q);
      return okCat && okQ;
    });
  }, [query, cat]);

  function addToCart(p) {
    setCart((prev) => {
      const ex = prev.find((i) => i.id === p.id);
      if (ex) return prev.map((i) => (i.id === p.id ? { ...i, qty: i.qty + 1 } : i));
      return [...prev, { ...p, qty: 1 }];
    });
  }
  function changeQty(id, d) {
    setCart((prev) =>
      prev
        .map((i) => (i.id === id ? { ...i, qty: i.qty + d } : i))
        .filter((i) => i.qty > 0)
    );
  }
  function removeItem(id) { setCart((prev) => prev.filter((i) => i.id !== id)); }

  // Enter en el buscador = comportamiento de escáner USB (emite código + Enter)
  function onSearchKey(e) {
    if (e.key !== "Enter") return;
    const q = query.trim();
    const exact = PRODUCTS.find((p) => p.cb === q);
    const target = exact || filtered[0];
    if (target) { addToCart(target); setQuery(""); }
  }

  const totals = useMemo(() => {
    let bruto = 0, iva = 0, base = 0;
    for (const i of cart) {
      const linea = i.precio * i.qty;          // precio con IVA incluido
      const lb = linea / (1 + i.iva);
      bruto += linea; base += lb; iva += linea - lb;
    }
    const desc = bruto * (descPct / 100);
    const factorDesc = bruto > 0 ? (bruto - desc) / bruto : 1;
    return {
      base: base * factorDesc,
      iva: iva * factorDesc,
      desc,
      total: bruto - desc,
    };
  }, [cart, descPct]);

  function finalizarVenta(cambio) {
    setVentasHoy((v) => ({ n: v.n + 1, total: v.total + totals.total }));
    if (!online) setPendientes((p) => p + 1);
    setCart([]); setDescPct(0); setPagando(false);
    setToast({
      msg: online ? "Venta registrada" : "Venta guardada · se sincronizará",
      sub: cambio > 0 ? `Cambio: ${money(cambio)}` : null,
    });
    setTimeout(() => setToast(null), 3200);
    searchRef.current?.focus();
  }

  function sincronizar() {
    if (!online || pendientes === 0) return;
    setPendientes(0);
    setToast({ msg: "Ventas sincronizadas con el servidor", sub: null });
    setTimeout(() => setToast(null), 2600);
  }

  return (
    <div style={{ background: C.bg, color: C.ink, fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif" }}
         className="min-h-screen w-full">
      {/* Header */}
      <header className="flex items-center justify-between px-5 py-3 border-b"
              style={{ borderColor: C.line, background: C.surface }}>
        <div className="flex items-center gap-3">
          <img src={LOGO} alt="Guapa Gourmet Market" style={{ width: 46, height: 46, borderRadius: "50%" }} />
          <div className="leading-tight">
            <div className="font-semibold tracking-tight" style={{ fontSize: 15 }}>Guapa Gourmet Market</div>
            <div style={{ fontSize: 11.5, color: C.muted, letterSpacing: "0.03em" }}>by Paola Rodríguez · Caja 1</div>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <div className="hidden sm:flex flex-col items-end mr-1 leading-tight">
            <span style={{ fontSize: 12, color: C.muted }}>Ventas de hoy</span>
            <span className="font-semibold" style={{ fontSize: 14 }}>
              {ventasHoy.n} · {money(ventasHoy.total)}
            </span>
          </div>
          {online && pendientes > 0 && (
            <button onClick={sincronizar}
              className="flex items-center gap-1.5 rounded-full px-3 py-1.5 transition"
              style={{ background: C.honeySoft, color: C.honey, fontSize: 12.5, fontWeight: 600 }}>
              <RefreshCw size={14} /> Sincronizar {pendientes}
            </button>
          )}
          <button onClick={() => setOnline((o) => !o)}
            className="flex items-center gap-1.5 rounded-full px-3 py-1.5 transition"
            style={{
              background: online ? C.greenSoft : "#FBECEC",
              color: online ? C.green : "#B4262B",
              fontSize: 12.5, fontWeight: 600,
            }}>
            {online ? <Wifi size={14} /> : <WifiOff size={14} />}
            {online ? "En línea" : "Sin conexión"}
          </button>
        </div>
      </header>

      <div className="flex flex-col lg:flex-row" style={{ minHeight: "calc(100vh - 62px)" }}>
        {/* Panel productos */}
        <section className="flex-1 p-4 sm:p-5">
          {/* Buscar / escanear */}
          <div className="flex items-center gap-2 rounded-2xl px-4 py-3 mb-3"
               style={{ background: C.surface, border: `1px solid ${C.line}` }}>
            <Search size={18} style={{ color: C.muted }} />
            <input
              ref={searchRef}
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={onSearchKey}
              placeholder="Buscar por nombre o escanear código de barras…"
              className="flex-1 bg-transparent outline-none"
              style={{ fontSize: 15 }}
            />
            <div className="flex items-center gap-1.5 rounded-lg px-2 py-1"
                 style={{ background: C.greenSoft, color: C.green, fontSize: 12 }}>
              <ScanLine size={14} /> Escáner listo
            </div>
          </div>

          {/* Categorías */}
          <div className="flex gap-2 mb-4 overflow-x-auto pb-1">
            {CATS.map((c) => (
              <button key={c} onClick={() => setCat(c)}
                className="whitespace-nowrap rounded-full px-3.5 py-1.5 transition"
                style={{
                  fontSize: 13, fontWeight: 500,
                  background: cat === c ? C.green : C.surface,
                  color: cat === c ? "#fff" : C.muted,
                  border: `1px solid ${cat === c ? C.green : C.line}`,
                }}>
                {c}
              </button>
            ))}
          </div>

          {/* Grid */}
          <div className="grid gap-3" style={{ gridTemplateColumns: "repeat(auto-fill, minmax(150px, 1fr))" }}>
            {filtered.map((p) => (
              <button key={p.id} onClick={() => addToCart(p)}
                className="text-left rounded-2xl p-3.5 transition active:scale-[0.98] hover:shadow-sm"
                style={{ background: C.surface, border: `1px solid ${C.line}` }}>
                <div className="grid place-items-center rounded-xl mb-3"
                     style={{ width: 40, height: 40, background: C.greenSoft }}>
                  <Leaf size={18} style={{ color: C.green }} />
                </div>
                <div className="font-medium leading-snug" style={{ fontSize: 13.5, minHeight: 36 }}>{p.nombre}</div>
                <div className="flex items-center justify-between mt-2">
                  <span className="font-semibold" style={{ fontSize: 15, fontVariantNumeric: "tabular-nums" }}>{money(p.precio)}</span>
                  <span style={{ fontSize: 11, color: C.muted }}>
                    {p.iva === 0 ? "IVA 0%" : `IVA ${Math.round(p.iva * 100)}%`}
                  </span>
                </div>
              </button>
            ))}
            {filtered.length === 0 && (
              <div className="col-span-full text-center py-16" style={{ color: C.muted }}>
                Sin resultados. Prueba otro nombre o código.
              </div>
            )}
          </div>
        </section>

        {/* Panel carrito */}
        <aside className="w-full lg:w-[380px] flex flex-col border-t lg:border-t-0 lg:border-l"
               style={{ borderColor: C.line, background: C.surface }}>
          <div className="flex items-center justify-between px-5 py-4 border-b" style={{ borderColor: C.line }}>
            <span className="font-semibold tracking-tight" style={{ fontSize: 15 }}>Venta actual</span>
            {cart.length > 0 && (
              <button onClick={() => { setCart([]); setDescPct(0); }}
                className="flex items-center gap-1" style={{ fontSize: 12.5, color: C.muted }}>
                <Trash2 size={14} /> Vaciar
              </button>
            )}
          </div>

          <div className="flex-1 overflow-y-auto px-3 py-2" style={{ maxHeight: 360 }}>
            {cart.length === 0 ? (
              <div className="text-center py-14 px-6" style={{ color: C.muted, fontSize: 14 }}>
                Escanea o toca un producto para empezar.
              </div>
            ) : (
              cart.map((i) => (
                <div key={i.id} className="flex items-center gap-3 rounded-xl px-2.5 py-2.5 mb-1">
                  <div className="flex-1 min-w-0">
                    <div className="font-medium truncate" style={{ fontSize: 13.5 }}>{i.nombre}</div>
                    <div style={{ fontSize: 12, color: C.muted, fontVariantNumeric: "tabular-nums" }}>
                      {money(i.precio)} c/u
                    </div>
                  </div>
                  <div className="flex items-center gap-1.5">
                    <button onClick={() => changeQty(i.id, -1)}
                      className="grid place-items-center rounded-lg" style={{ width: 26, height: 26, background: C.bg }}>
                      <Minus size={14} />
                    </button>
                    <span className="text-center font-semibold" style={{ width: 22, fontSize: 14, fontVariantNumeric: "tabular-nums" }}>{i.qty}</span>
                    <button onClick={() => changeQty(i.id, 1)}
                      className="grid place-items-center rounded-lg" style={{ width: 26, height: 26, background: C.greenSoft, color: C.green }}>
                      <Plus size={14} />
                    </button>
                  </div>
                  <div className="w-[70px] text-right font-semibold" style={{ fontSize: 13.5, fontVariantNumeric: "tabular-nums" }}>
                    {money(i.precio * i.qty)}
                  </div>
                </div>
              ))
            )}
          </div>

          {/* Descuento + totales */}
          <div className="px-5 pt-3 pb-4 border-t" style={{ borderColor: C.line }}>
            <div className="flex items-center justify-between mb-3">
              <span style={{ fontSize: 13.5, color: C.muted }}>Descuento</span>
              <div className="flex items-center gap-1">
                {[0, 5, 10, 15].map((d) => (
                  <button key={d} onClick={() => setDescPct(d)}
                    className="rounded-lg px-2.5 py-1 transition"
                    style={{
                      fontSize: 12.5, fontWeight: 600,
                      background: descPct === d ? C.green : C.bg,
                      color: descPct === d ? "#fff" : C.muted,
                    }}>{d}%</button>
                ))}
              </div>
            </div>

            <Row label="Subtotal" value={money(totals.base)} muted />
            <Row label="IVA" value={money(totals.iva)} muted />
            {totals.desc > 0 && <Row label={`Descuento (${descPct}%)`} value={`− ${money(totals.desc)}`} accent />}
            <div className="flex items-center justify-between mt-2 pt-2 border-t" style={{ borderColor: C.line }}>
              <span className="font-semibold" style={{ fontSize: 16 }}>Total</span>
              <span className="font-bold" style={{ fontSize: 22, fontVariantNumeric: "tabular-nums" }}>{money(totals.total)}</span>
            </div>

            <button
              disabled={cart.length === 0}
              onClick={() => setPagando(true)}
              className="w-full mt-4 rounded-2xl py-3.5 font-semibold transition active:scale-[0.99]"
              style={{
                fontSize: 16,
                background: cart.length === 0 ? "#D8DDD6" : C.green,
                color: cart.length === 0 ? "#9AA097" : "#fff",
                cursor: cart.length === 0 ? "default" : "pointer",
              }}>
              Cobrar {cart.length > 0 && money(totals.total)}
            </button>
          </div>
        </aside>
      </div>

      {pagando && (
        <PaymentSheet total={totals.total} online={online}
          onClose={() => setPagando(false)} onDone={finalizarVenta} />
      )}

      {toast && (
        <div className="fixed left-1/2 bottom-6 -translate-x-1/2 flex items-center gap-2.5 rounded-2xl px-4 py-3 shadow-lg"
             style={{ background: C.ink, color: "#fff", zIndex: 60 }}>
          <div className="grid place-items-center rounded-full" style={{ width: 22, height: 22, background: C.green }}>
            <Check size={14} />
          </div>
          <div className="leading-tight">
            <div style={{ fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
            {toast.sub && <div style={{ fontSize: 12.5, opacity: 0.8 }}>{toast.sub}</div>}
          </div>
        </div>
      )}
    </div>
  );
}

function Row({ label, value, muted, accent }) {
  return (
    <div className="flex items-center justify-between py-0.5">
      <span style={{ fontSize: 13.5, color: muted ? C.muted : C.ink }}>{label}</span>
      <span style={{ fontSize: 13.5, color: accent ? C.honey : C.ink, fontVariantNumeric: "tabular-nums", fontWeight: accent ? 600 : 400 }}>{value}</span>
    </div>
  );
}

function PaymentSheet({ total, online, onClose, onDone }) {
  const [pagos, setPagos] = useState([]);
  const [metodo, setMetodo] = useState("efectivo");
  const [monto, setMonto] = useState("");

  const pagado = pagos.reduce((s, p) => s + p.monto, 0);
  const restante = Math.max(0, total - pagado);
  const excedente = Math.max(0, pagado - total);
  const cubierto = pagado >= total;

  function agregarPago() {
    const m = metodo === "efectivo" && !monto ? restante : Number(monto);
    if (!m || m <= 0) return;
    setPagos((p) => [...p, { metodo, monto: m }]);
    setMonto("");
  }
  const metaOf = (id) => METODOS.find((m) => m.id === id);

  return (
    <div className="fixed inset-0 flex items-end sm:items-center justify-center p-0 sm:p-4"
         style={{ background: "rgba(20,26,22,0.45)", zIndex: 50 }} onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()}
        className="w-full sm:max-w-[440px] rounded-t-3xl sm:rounded-3xl p-5"
        style={{ background: C.surface }}>
        <div className="flex items-center justify-between mb-4">
          <span className="font-semibold tracking-tight" style={{ fontSize: 17 }}>Cobrar {money(total)}</span>
          <button onClick={onClose} className="grid place-items-center rounded-full"
                  style={{ width: 30, height: 30, background: C.bg }}><X size={16} /></button>
        </div>

        {/* Métodos */}
        <div className="grid grid-cols-5 gap-2 mb-4">
          {METODOS.map((m) => {
            const Icon = m.icon; const on = metodo === m.id;
            return (
              <button key={m.id} onClick={() => setMetodo(m.id)}
                className="flex flex-col items-center gap-1.5 rounded-2xl py-2.5 transition"
                style={{
                  background: on ? m.color : C.bg,
                  color: on ? "#fff" : C.muted,
                  border: `1px solid ${on ? m.color : C.line}`,
                }}>
                <Icon size={18} />
                <span style={{ fontSize: 10.5, fontWeight: 600 }}>{m.label}</span>
              </button>
            );
          })}
        </div>

        {/* Monto */}
        <div className="flex items-center gap-2 rounded-2xl px-4 py-3 mb-3" style={{ background: C.bg }}>
          <span style={{ fontSize: 18, color: C.muted }}>$</span>
          <input
            type="number" value={monto} onChange={(e) => setMonto(e.target.value)}
            placeholder={metodo === "efectivo" ? `${restante}  (recibido)` : `${restante}`}
            className="flex-1 bg-transparent outline-none" style={{ fontSize: 18, fontWeight: 600 }} />
          <button onClick={agregarPago}
            className="rounded-xl px-3.5 py-2 font-semibold" style={{ background: C.green, color: "#fff", fontSize: 13.5 }}>
            Agregar
          </button>
        </div>

        {/* Pagos añadidos */}
        {pagos.length > 0 && (
          <div className="mb-3">
            {pagos.map((p, idx) => {
              const meta = metaOf(p.metodo);
              return (
                <div key={idx} className="flex items-center justify-between py-1.5">
                  <span className="flex items-center gap-2" style={{ fontSize: 13.5 }}>
                    <span className="inline-block rounded-full" style={{ width: 8, height: 8, background: meta.color }} />
                    {meta.label}
                  </span>
                  <span className="flex items-center gap-2" style={{ fontSize: 13.5, fontVariantNumeric: "tabular-nums" }}>
                    {money(p.monto)}
                    <button onClick={() => setPagos((ps) => ps.filter((_, i) => i !== idx))}><X size={13} style={{ color: C.muted }} /></button>
                  </span>
                </div>
              );
            })}
          </div>
        )}

        {/* Estado */}
        <div className="rounded-2xl px-4 py-3 mb-4" style={{ background: cubierto ? C.greenSoft : C.honeySoft }}>
          {cubierto ? (
            <div className="flex items-center justify-between">
              <span style={{ fontSize: 14, color: C.green, fontWeight: 600 }}>Pago completo</span>
              {excedente > 0 && <span style={{ fontSize: 14, color: C.green, fontWeight: 600 }}>Cambio {money(excedente)}</span>}
            </div>
          ) : (
            <div className="flex items-center justify-between">
              <span style={{ fontSize: 14, color: C.honey, fontWeight: 600 }}>Restante</span>
              <span style={{ fontSize: 14, color: C.honey, fontWeight: 600, fontVariantNumeric: "tabular-nums" }}>{money(restante)}</span>
            </div>
          )}
        </div>

        <button disabled={!cubierto} onClick={() => onDone(excedente)}
          className="w-full rounded-2xl py-3.5 font-semibold transition active:scale-[0.99]"
          style={{
            fontSize: 16,
            background: cubierto ? C.green : "#D8DDD6",
            color: cubierto ? "#fff" : "#9AA097",
            cursor: cubierto ? "pointer" : "default",
          }}>
          {online ? "Confirmar venta" : "Guardar venta (offline)"}
        </button>
      </div>
    </div>
  );
}
